import"./nav-CoHLXmV3.js";/* empty css              */document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".accordion-header").forEach(o=>{o.addEventListener("click",()=>{const e=o.parentElement,t=e.querySelector(".accordion-content"),n=e.classList.contains("active");document.querySelectorAll(".accordion-item").forEach(c=>{c!==e&&(c.classList.remove("active"),c.querySelector(".accordion-content").style.maxHeight=null)}),n?(e.classList.remove("active"),t.style.maxHeight=null):(e.classList.add("active"),t.style.maxHeight=t.scrollHeight+"px")})})});
